19	const cache = new Map<DialectOptions, Dialect>();
20	
21	/**
22	 * Factory function for building Dialect objects.
23	 * When called repeatedly with same options object returns the cached Dialect,
24	 * to avoid the cost of creating it again.
25	 */
26	export const createDialect = (options: DialectOptions): Dialect => {
27	  let dialect = cache.get(options);
28	  if (!dialect) {
29	    dialect = dialectFromOptions(options);
30	    cache.set(options, dialect);
31	  }
32	  return dialect;
33	};
34	
35	const dialectFromOptions = (dialectOptions: DialectOptions): Dialect => ({
36	  tokenizer: new Tokenizer(dialectOptions.tokenizerOptions, dialectOptions.name),
37	  formatOptions: processDialectFormatOptions(dialectOptions.formatOptions),
38	});
