41	  options: DialectFormatOptions
42	): ProcessedDialectFormatOptions => ({
43	  alwaysDenseOperators: options.alwaysDenseOperators || [],
44	  onelineClauses: Object.fromEntries(options.onelineClauses.map(name => [name, true])),
45	  tabularOnelineClauses: Object.fromEntries(
