// so the pipe body reuses the same clause machinery as traditional queries.
// Also retags a GROUP BY belonging to a pipe AGGREGATE clause to PIPE_GROUP_BY,
// so it nests inside the AGGREGATE clause instead of parsing as a standalone clause.
function promotePipeClauses(tokens: Token[]): Token[] {
  let expectClauseKw = false; // previous non-comment token was |>
  let aggregateActive = false; // inside a pipe AGGREGATE clause, awaiting its GROUP BY
  let parenDepth = 0;
  let aggregateDepth = 0; // paren depth at which the active AGGREGATE clause started

  return tokens.map(token => {
    if (token.type === TokenType.PIPE_OPERATOR) {
      expectClauseKw = true;
      aggregateActive = false;
      return token;
    }
    if (token.type === TokenType.LINE_COMMENT || token.type === TokenType.BLOCK_COMMENT) {
      return token; // keep state across comments
