    const result = format(
      `FROM users |> WHERE age > 21 |> SELECT name, age |> ORDER BY age |> LIMIT 10`
    );
    expect(result).toBe(dedent`
      FROM
        users
      |> WHERE
        age > 21
      |> SELECT
        name,
        age
      |> ORDER BY
        age
      |> LIMIT 10
    `);
  });

  it('tokenizes |> as a distinct operator, not bitwise | and >', () => {
    // A traditional query with a bitwise OR still works
    expect(format(`SELECT a | b FROM t`)).toBe(dedent`
      SELECT
        a | b
      FROM
        t
    `);
  });

  it('places indented pipe clauses (WHERE, SELECT, EXTEND, SET, DROP) on a new indented line', () => {
    const result = format(
      `FROM t |> EXTEND a + b AS c |> SET x = 1 |> DROP y |> WHERE z > 0`
    );
    expect(result).toBe(dedent`
      FROM
        t
      |> EXTEND
        a + b AS c
      |> SET
        x = 1
      |> DROP
        y
      |> WHERE
        z > 0
    `);
  });

  it('keeps one-line pipe clauses (LIMIT, JOIN, AS) on the same line as the keyword', () => {
    const result = format(
      `FROM t |> AS foo |> JOIN other ON t.id = other.id |> LIMIT 10`
    );
    expect(result).toBe(dedent`
      FROM
        t
      |> AS foo
      |> JOIN other ON t.id = other.id
      |> LIMIT 10
    `);
  });

  it('formats JOIN variants as one-line pipe clauses', () => {
    const result = format(`FROM t |> LEFT OUTER JOIN u ON t.a = u.a`);
    expect(result).toBe(dedent`
      FROM
        t
      |> LEFT OUTER JOIN u ON t.a = u.a
    `);
  });

  it('nests GROUP BY inside a pipe AGGREGATE clause with its own indentation', () => {
    const result = format(`FROM orders |> AGGREGATE SUM(cost) AS total GROUP BY category`);
    expect(result).toBe(dedent`
      FROM
        orders
      |> AGGREGATE
        SUM(cost) AS total
        GROUP BY
          category
    `);
  });

  it('formats a pipe AGGREGATE clause without GROUP BY', () => {
    const result = format(`FROM t |> AGGREGATE COUNT(*) AS total`);
    expect(result).toBe(dedent`
      FROM
        t
      |> AGGREGATE
        COUNT(*) AS total
    `);
  });

  it('does not treat a GROUP BY inside an AGGREGATE subquery as the aggregate sub-clause', () => {
    const result = format(
      `FROM t |> AGGREGATE SUM((SELECT y FROM z GROUP BY w)) GROUP BY a`
    );
    expect(result).toBe(dedent`
      FROM
        t
      |> AGGREGATE
        SUM(
          (
            SELECT
              y
            FROM
              z
            GROUP BY
              w
          )
        )
        GROUP BY
          a
    `);
  });

  it('formats pipe queries nested inside parentheses as subqueries', () => {
