    expect(result).toBe(dedent`
      SELECT
        *
      FROM
        (
          FROM
            t
          |> WHERE
            x > 1
          |> SELECT
            x
        )
    `);
  });

  it('attaches a semicolon after the final pipe step', () => {
    const result = format(`FROM t |> SELECT x;`);
    expect(result).toBe(dedent`
      FROM
        t
      |> SELECT
        x;
    `);
  });

  it('formats mixed pipe and traditional statements independently', () => {
    const result = format(`FROM t |> SELECT x;\nSELECT a FROM b;`);
    expect(result).toBe(dedent`
      FROM
        t
      |> SELECT
        x;

      SELECT
        a
      FROM
        b;
    `);
  });

