  it('preserves original case of pipe keywords when keywordCase is preserve', () => {
    const result = format(`from t |> aggregate count(*) group by x`, {
      keywordCase: 'preserve',
    });
    expect(result).toBe(dedent`
      from
        t
      |> aggregate
        count(*)
        group by
          x
    `);
  });

  it('formats comments between the pipe operator and its clause keyword', () => {
    const result = format(`FROM t |> /* c */ WHERE x > 1`);
    expect(result).toBe(dedent`
      FROM
        t
      |> /* c */ WHERE
        x > 1
    `);
  });
}
